static void *psmgr_seq_start(struct seq_file *seq, loff_t *pos)
	__acquires(pn->session_lock)
{
	struct psmgr_net *pn = psmgr_net(seq_file_net(seq));
	loff_t bucket = *pos / PSMGR_SESSION_HTABLE_SZ;
	loff_t idx    = *pos % PSMGR_SESSION_HTABLE_SZ;
	struct list_head *head;
	struct psmgr_session *sess;
	loff_t count = 0;

	spin_lock_bh(&pn->session_lock);

	if (*pos == 0) {
		seq_printf(seq, "%-10s %-8s %-12s %-10s %-12s %-14s %-12s %s\n",
				   "session_id", "role", "state", "peer_id",
				   "write_count", "data_msgs_rx", "seq_errors", "age_ms");
		return SEQ_START_TOKEN;
	}

	/* Walk the hash table to find the entry at position *pos - 1 */
	(void)bucket; (void)idx;
	for (bucket = 0; bucket < PSMGR_SESSION_HTABLE_SZ; bucket++) {
		head = &pn->session_table[bucket];
		list_for_each_entry(sess, head, node) {
			if (count == *pos - 1)
				return sess;
			count++;
		}
	}
	return NULL;
}

