/* -------------------------------------------------------------------------
 * Session ID allocator
 * ---------------------------------------------------------------------- */

static atomic_t psmgr_id_counter = ATOMIC_INIT(1);

u32 psmgr_session_alloc_id(void)
{
	return (u32)atomic_inc_return(&psmgr_id_counter);
}

/* -------------------------------------------------------------------------
 * Session table operations
 * ---------------------------------------------------------------------- */

struct psmgr_session *psmgr_session_lookup(struct psmgr_net *pn, u32 id)
{
	struct list_head *bucket = psmgr_session_bucket(pn, id);
	struct psmgr_session *sess;

	list_for_each_entry(sess, bucket, node) {
		if (sess->session_id == id)
			return sess;
	}
	return NULL;
}

void psmgr_session_put(struct psmgr_session *sess)
{
	if (refcount_dec_and_test(&sess->refcnt)) {
		kfree(sess->desc);
		kfree(sess);
	}
}

/* -------------------------------------------------------------------------
 * Validation helpers
 * ---------------------------------------------------------------------- */

static int psmgr_validate_enc_class(u8 enc_class)
{
	return (enc_class == PSMGR_CLASS_BASIC   ||
			enc_class == PSMGR_CLASS_EXTENDED ||
			enc_class == PSMGR_CLASS_INITIATOR_EXT) ? 0 : -EINVAL;
}

static int psmgr_validate_xfrm_type(u8 xfrm_type)
{
	return (xfrm_type == PSMGR_XFRM_SCATTER ||
			xfrm_type == PSMGR_XFRM_WINDOW  ||
			xfrm_type == PSMGR_XFRM_COMMIT  ||
			xfrm_type == PSMGR_XFRM_REFLECT) ? 0 : -EINVAL;
}

static int psmgr_validate_enc_mode(u8 enc_class, u8 enc_mode)
{
	switch (enc_class) {
	case PSMGR_CLASS_BASIC:
		return (enc_mode == PSMGR_MODE_LINEAR ||
				enc_mode == PSMGR_MODE_FOLD) ? 0 : -EINVAL;
	case PSMGR_CLASS_EXTENDED:
		return (enc_mode == PSMGR_MODE_LINEAR    ||
				enc_mode == PSMGR_MODE_INTERLEAVE ||
				enc_mode == PSMGR_MODE_FOLD) ? 0 : -EINVAL;
	case PSMGR_CLASS_INITIATOR_EXT:
		return (enc_mode == PSMGR_MODE_INTERLEAVE ||
				enc_mode == PSMGR_MODE_FOLD) ? 0 : -EINVAL;
	default:
		return -EINVAL;
	}
}

