505	 * setsockopt
506	 * ---------------------------------------------------------------------- */
507	
508	int psmgr_setsockopt(struct socket *sock, int level, int optname,
509						 sockptr_t optval, unsigned int optlen)
510	{
511		struct sock *sk = sock->sk;
512		struct psmgr_sock *psk = psmgr_sk(sk);
513		struct psmgr_session *sess = psk->session;
514		struct psmgr_net *pn = psmgr_net(sock_net(sk));
515		int ret = 0;
516	
517		if (level != PSMGR_SOL)
518			return -ENOPROTOOPT;
519		if (!sess)
520			return -ENOTCONN;
521	
522		lock_sock(sk);
523	
524		switch (optname) {
525	
526		case PSMGR_OPT_SET_ROLE: {
527			struct psmgr_opt_role opt;
528			if (optlen < sizeof(opt)) { ret = -EINVAL; break; }
529			if (copy_from_sockptr(&opt, optval, sizeof(opt))) { ret = -EFAULT; break; }
530			if (sess->state != PSMGR_STATE_INIT) { ret = -EISCONN; break; }
531			ret = psmgr_validate_role(opt.role);
532			if (ret) break;
533			sess->role = opt.role;
534			if (opt.role == PSMGR_ROLE_MANAGED || opt.role == PSMGR_ROLE_FORWARD) {
535				sess->state = PSMGR_STATE_NEGO_1;
536				if (opt.role == PSMGR_ROLE_FORWARD) {
537					/*
538					 * FORWARD sessions have no parameters to negotiate.
539					 * Advance directly to NEGO_2 so connect() finds the
540					 * session in the expected pre-connect state.
541					 */
542					sess->state = PSMGR_STATE_NEGO_2;
543				}
544			} else {
545				sess->state = PSMGR_STATE_NEGO_1;
546			}
547			pr_debug("psmgr: session %u role=%u state=%u\n",
548					 sess->session_id, opt.role, sess->state);
549			break;
550		}
551	
552		/*
553		 * PSMGR_OPT_NEGO_1: INITIATOR contributes transport parameters.
554		 * enc_class governs which enc_modes the RESPONDER may use.
555		 * xfrm_type selects the transform the processing path will apply.
556		 */
557		case PSMGR_OPT_NEGO_1: {
558			struct psmgr_nego_1 opt;
559			if (optlen < sizeof(opt)) { ret = -EINVAL; break; }
560			if (copy_from_sockptr(&opt, optval, sizeof(opt))) { ret = -EFAULT; break; }
561			if (sess->role != PSMGR_ROLE_INITIATOR) { ret = -EOPNOTSUPP; break; }
562			if (sess->state != PSMGR_STATE_NEGO_1) { ret = -EPROTO; break; }
563			ret = psmgr_validate_enc_class(opt.enc_class);
564			if (ret) break;
565			ret = psmgr_validate_xfrm_type(opt.xfrm_type);
566			if (ret) break;
567			sess->enc_class     = opt.enc_class;
568			sess->ctx.xfrm_type = opt.xfrm_type;
569			sess->state         = PSMGR_STATE_NEGO_2;
570			pr_debug("psmgr: session %u INITIATOR nego1: enc_class=%u xfrm_type=%u\n",
571					 sess->session_id, opt.enc_class, opt.xfrm_type);
572			break;
573		}
574	
575		/*
576		 * PSMGR_OPT_NEGO_2: RESPONDER contributes processing parameters.
577		 * enc_mode and proc_param are validated against the RESPONDER-side spec.
578		 */
579		case PSMGR_OPT_NEGO_2: {
580			struct psmgr_nego_2 opt;
581			if (optlen < sizeof(opt)) { ret = -EINVAL; break; }
582			if (copy_from_sockptr(&opt, optval, sizeof(opt))) { ret = -EFAULT; break; }
583			if (sess->role != PSMGR_ROLE_RESPONDER) { ret = -EOPNOTSUPP; break; }
584			if (sess->state != PSMGR_STATE_NEGO_1) { ret = -EPROTO; break; }
585			ret = psmgr_validate_enc_mode(PSMGR_CLASS_EXTENDED, opt.enc_mode);
586			if (ret) break;
587			ret = psmgr_validate_proc_param(opt.enc_mode, opt.proc_param);
588			if (ret) break;
589			sess->ctx.enc_mode   = opt.enc_mode;
590			sess->ctx.proc_param = opt.proc_param;
591			sess->state          = PSMGR_STATE_NEGO_2;
592			pr_debug("psmgr: session %u RESPONDER nego2: enc_mode=%u proc_param=%u\n",
593					 sess->session_id, opt.enc_mode, opt.proc_param);
594			break;
595		}
596	
597		ca

597		case PSMGR_OPT_LOCAL_CTX: {
598			struct psmgr_local_ctx opt;
599			u32 param_max;
600			if (optlen < sizeof(opt)) { ret = -EINVAL; break; }
601			if (copy_from_sockptr(&opt, optval, sizeof(opt))) { ret = -EFAULT; break; }
602			if (sess->role != PSMGR_ROLE_MANAGED) { ret = -EOPNOTSUPP; break; }
603			if (sess->state != PSMGR_STATE_NEGO_1) { ret = -EPROTO; break; }
604			ret = psmgr_validate_xfrm_type(opt.xfrm_type);
605			if (ret) break;
606			ret = psmgr_validate_enc_mode(PSMGR_CLASS_EXTENDED, opt.enc_mode);
607			if (ret) break;
608			switch (opt.xfrm_type) {
609			case PSMGR_XFRM_SCATTER:
610				param_max = (opt.enc_mode == PSMGR_MODE_LINEAR) ? 63 :
611							(opt.enc_mode == PSMGR_MODE_INTERLEAVE) ? 31 : 15;
612				break;
613			case PSMGR_XFRM_WINDOW:
614			case PSMGR_XFRM_REFLECT:
615				param_max = (opt.enc_mode == PSMGR_MODE_LINEAR) ? 127 :
616							(opt.enc_mode == PSMGR_MODE_INTERLEAVE) ? 63 : 31;
617				break;
618			case PSMGR_XFRM_COMMIT:
619				param_max = (opt.enc_mode == PSMGR_MODE_LINEAR) ? 31 :
620							(opt.enc_mode == PSMGR_MODE_INTERLEAVE) ? 15 : 7;
621				break;
622			default:
623				ret = -EINVAL;
624				goto out_unlock;
625			}
626			if (opt.proc_param > param_max) { ret = -ERANGE; break; }
627			sess->ctx.xfrm_type  = opt.xfrm_type;
628			sess->ctx.enc_mode   = opt.enc_mode;
629			sess->ctx.window_sz  = opt.window_sz;
630			sess->ctx.proc_param = opt.proc_param;
631			sess->validated      = 1;
632			sess->state          = PSMGR_STATE_ESTABLISHED;
633			pr_debug("psmgr: session %u MANAGED established: "
634					 "xfrm=%u enc_mode=%u proc_param=%u\n",
635					 sess->session_id, opt.xfrm_type,
636					 opt.enc_mode, opt.proc_param);
637			break;
638		}
639	
640		case PSMGR_OPT_WINDOW: {
641			struct psmgr_opt_window opt;
642			if (optlen < sizeof(opt)) { ret = -EINVAL; break; }
643			if (copy_from_sockptr(&opt, optval, sizeof(opt))) { ret = -EFAULT; break; }
644			if (sess->role != PSMGR_ROLE_RESPONDER) { ret = -EOPNOTSUPP; break; }
645			if (sess->state != PSMGR_STATE_NEGO_2 &&
646				sess->state != PSMGR_STATE_ESTABLISHED) { ret = -EPROTO; break; }
647			if (opt.window_sz == 0 || opt.window_sz > PSMGR_BUF_DATA_SZ) {
648				ret = -ERANGE; break;
649			}
650			sess->ctx.window_sz = opt.window_sz;
651			/* If already connected, propagate to peer (initiator) context */
652			spin_lock_bh(&sess->lock);
653			if (sess->peer)
654				sess->peer->ctx.window_sz = opt.window_sz;
655			spin_unlock_bh(&sess->lock);
656			pr_debug("psmgr: session %u RESPONDER window_sz=%u\n",
657					 sess->session_id, opt.window_sz);
658			break;
659		}
660	
661		case PSMGR_OPT_EXEC: {
662			if (sess->state != PSMGR_STATE_ESTABLISHED || !sess->validated) {
663				ret = -ENOTCONN; break;
664			}
665			psmgr_session_get(sess);
666			release_sock(sk);
667			ret = psmgr_exec(sess);
668			if (ret == 0)
669				atomic64_inc(&pn->total_exec_calls);
670			psmgr_session_put(sess);
671			lock_sock(sk);
672			break;
673		}
674	
675		case PSMGR_OPT_RESET: {
676			if (!sess->validated) { ret = -ENOTCONN; break; }
677			spin_lock_bh(&sess->lock);
678			if (sess->desc->token != 0) {
679				spin_unlock_bh(&sess->lock);
680				ret = -EPROTO;
681				break;
682			}
683			memset(sess->desc, 0, sizeof(*sess->desc));
684			sess->next_seq = 0;
685			spin_unlock_bh(&sess->lock);
686			pr_debug("psmgr: session %u desc reset\n", sess->session_id);
687			break;
688		}
689	
690		default:
691			ret = -ENOPROTOOPT;
692			break;
693		}
694	
695	out_unlock:
696		release_sock(sk);
697		return ret;
698	}
