422		struct sock *sk = sock->sk;
423		struct psmgr_sock *psk = psmgr_sk(sk);
424		struct psmgr_session *sess = psk->session;
425		struct psmgr_msghdr hdr;
426		u8 *payload = NULL;
427		u16 payload_len;
428		int ret = 0;
429	
430		if (!sess || !sess->validated)
431			return -ENOTCONN;
432		if (len < PSMGR_MSGHDR_SZ)
433			return -EINVAL;
434		if (len > PSMGR_MSG_MAX_SZ)
435			return -EMSGSIZE;
436	
437		if (sess->role == PSMGR_ROLE_FORWARD) {
438			/*
439			 * FORWARD sessions initiator messages to the peer without processing.
440			 * The peer must be connected; if not, the session is not yet usable.
441			 */
442			spin_lock_bh(&sess->lock);
443			if (!sess->peer || !sess->validated) {
444				spin_unlock_bh(&sess->lock);
445				return -ENOTCONN;
446			}
447			sess->stats.data_msgs_rx++;
448			sess->stats.last_rx = ktime_get();
449			if (sess->peer->sk)
450				sess->peer->sk->sk_data_ready(sess->peer->sk);
451			spin_unlock_bh(&sess->lock);
452			return (int)len;
453		}
454	
455		if (copy_from_iter(&hdr, PSMGR_MSGHDR_SZ, &msg->msg_iter) != PSMGR_MSGHDR_SZ)
456			return -EFAULT;
457	
458		if ((hdr.session_id_lo & 0xFF) != (sess->session_id & 0xFF)) {
459			pr_debug("psmgr: session %u session_id_lo mismatch: "
460					 "expected 0x%02x got 0x%02x\n",
461					 sess->session_id,
462					 (u8)(sess->session_id & 0xFF),
463					 hdr.session_id_lo);
464			return -EBADFD;
465		}
466	
467		if (hdr.msg_type == PSMGR_MSG_WINDOW_UPD) {
468			struct psmgr_window_upd_payload wup;
469			u16 wup_len;
470	
471			if (sess->role != PSMGR_ROLE_RESPONDER)
472				return -EOPNOTSUPP;
473	
474			wup_len = min_t(u16, hdr.payload_len, (u16)sizeof(wup));
475			if (wup_len < sizeof(wup))
476				return -EINVAL;
477			if (copy_from_iter(&wup, sizeof(wup),
478							   &msg->msg_iter) != sizeof(wup))
479				return -EFAULT;
480			if (wup.new_window_sz == 0 ||
481				wup.new_window_sz > PSMGR_BUF_DATA_SZ)
482				return -ERANGE;
483	
484			spin_lock_bh(&sess->lock);
485			ret = psmgr_check_seq(sess, hdr.seq, hdr.msg_type);
486			if (ret == 0) {
487				sess->ctx.window_sz = wup.new_window_sz;
488				sess->stats.last_rx = ktime_get();
489				pr_debug("psmgr: session %u WINDOW_UPD new_window_sz=%u\n",
490						 sess->ses

490						 sess->session_id, wup.new_window_sz);
491				ret = (int)len;
492			}
493			spin_unlock_bh(&sess->lock);
494			return ret;
495		}
496	
497		switch (hdr.msg_type) {
498		case PSMGR_MSG_DATA:
499			payload_len = min_t(u16, hdr.payload_len, PSMGR_BUF_DATA_SZ);
500			break;
501		case PSMGR_MSG_COMMIT_REQ:
502			payload_len = min_t(u16, hdr.payload_len,
503								(u16)sizeof(struct psmgr_commit_req_payload));
504			break;
505		case PSMGR_MSG_CTRL:
506			payload_len = min_t(u16, hdr.payload_len,
507								(u16)sizeof(struct psmgr_ctrl_payload));
508			break;
509		default:
510			payload_len = 0;
511			break;
512		}
513	
514		if (payload_len > 0) {
515			payload = kmalloc(payload_len, GFP_KERNEL);
516			if (!payload)
517				return -ENOMEM;
518			if (copy_from_iter(payload, payload_len,
519							   &msg->msg_iter) != payload_len) {
520				kfree(payload);
521				return -EFAULT;
522			}
523		}
524	
525		spin_lock_bh(&sess->lock);
526	
527		ret = psmgr_check_seq(sess, hdr.seq, hdr.msg_type);
528		if (ret) {
529			spin_unlock_bh(&sess->lock);
530			kfree(payload);
531			return ret;
532		}
533	
534		switch (hdr.msg_type) {
535	
536		case PSMGR_MSG_DATA:
537			ret = psmgr_process_data(sess, payload, payload_len);
538			if (ret >= 0) ret = (int)len;
539			break;
540	
541		case PSMGR_MSG_COMMIT_REQ:
542			ret = psmgr_process_commit_req(sess, payload, payload_len);
543			if (ret >= 0) ret = (int)len;
544			break;
545	
546		case PSMGR_MSG_PROBE:
547			sess->stats.probe_msgs_rx++;
548			sess->stats.last_rx = ktime_get();
549			ret = (int)len;
550			break;
551	
552		case PSMGR_MSG_CTRL:
553			ret = psmgr_process_ctrl(sess, payload, payload_len);
554			if (ret >= 0) ret = (int)len;
555			break;
556	
557		default:
558			ret = -EPROTO;
559			break;
560		}
561	
562		spin_unlock_bh(&sess->lock);
563		kfree(payload);
564	
565		return ret;
566	}
