568	/* -------------------------------------------------------------------------
569	 * recvmsg
570	 * ---------------------------------------------------------------------- */
571	
572	struct psmgr_desc_export {
573		u8   data[PSMGR_BUF_DATA_SZ];
574		u32  write_count;
575		u32  token;
576		u8   handler_set;
577		u8   reserved[7];
578	};
579	
580	int psmgr_recvmsg(struct socket *sock, struct msghdr *msg, size_t len,
581			  int flags)
582	{
583		struct sock *sk = sock->sk;
584		struct psmgr_sock *psk = psmgr_sk(sk);
585		struct psmgr_session *sess = psk->session;
586		struct psmgr_desc_export exp;
587	
588		if (!sess || !sess->validated)
589			return -ENOTCONN;
590	
591		if (len < sizeof(exp))
592			return -EINVAL;
593	
594		memset(&exp, 0, sizeof(exp));
595		spin_lock_bh(&sess->lock);
596		memcpy(exp.data, sess->desc->data, PSMGR_BUF_DATA_SZ);
597		exp.write_count  = sess->desc->write_count;
598		exp.token  = sess->desc->token;
599		exp.handler_set = (sess->desc->handler != NULL) ? 1 : 0;
600		spin_unlock_bh(&sess->lock);
601	
602		if (copy_to_iter(&exp, sizeof(exp), &msg->msg_iter) != sizeof(exp))
603			return -EFAULT;
604	
605		return sizeof(exp);
606	}
