609	 * exec path
610	 * ---------------------------------------------------------------------- */
611	
612	int psmgr_exec(struct psmgr_session *sess)
613	{
614		struct psmgr_desc *pb = sess->desc;
615		u8 data_copy[PSMGR_BUF_DATA_SZ];
616		u32 token;
617		u32 write_count;
618		psmgr_handler_fn_t fn;
619	
620		spin_lock_bh(&sess->lock);
621		token = pb->token;
622		write_count = pb->write_count;
623		fn         = pb->handler;
624		memcpy(data_copy, pb->data, PSMG

620		spin_lock_bh(&sess->lock);
621		token = pb->token;
622		write_count = pb->write_count;
623		fn         = pb->handler;
624		memcpy(data_copy, pb->data, PSMGR_BUF_DATA_SZ);
625		sess->stats.exec_calls++;
626		spin_unlock_bh(&sess->lock);
627	
628		if (write_count != PSMGR_BUF_COMMITTED) {
629			pr_debug("psmgr: session %u exec rejected: not finalized\n",
630					 sess->session_id);
631			return -EPROTO;
632		}
633	
634		if (token == 0) {
635			pr_debug("psmgr: session %u exec rejected: token not set\n",
636					 sess->session_id);
637			return -EACCES;
638		}
639	
640		if (fn == NULL) {
641			pr_debug("psmgr: session %u exec rejected: handler not set\n",
642					 sess->session_id);
643			return -ENOENT;
644		}
645	
646		fn(sess, data_copy, PSMGR_BUF_DATA_SZ);
647	
648		spin_lock_bh(&sess->lock);
649		memcpy(pb->data, data_copy, PSMGR_BUF_DATA_SZ);
650		spin_unlock_bh(&sess->lock);
651	
652		return 0;

200	}
